// src/pages/HomePage.jsx
import React, { useState, useEffect } from "react";
import Layout from "../components/Layout";
import GlobeLogo from "../components/GlobeLogo";
import MapPanel from "../components/MapPanel";
import { Btn, VoiceWave } from "../components/UI";

const HOW_IT_WORKS = [
  { step: "01", icon: "📍", title: "Detect Location", desc: "We detect your GPS and find the nearest station instantly." },
  { step: "02", icon: "🎤", title: "Speak Destination", desc: "Say your destination. VISTA understands natural speech." },
  { step: "03", icon: "🚂", title: "Train Guidance", desc: "Get next train, platform, timing & direction." },
  { step: "04", icon: "🚌", title: "Last Mile Guide", desc: "Find buses, autos, or cabs to reach your final stop." },
];

export default function HomePage({ onNavigate, speak }) {
  const [splashVisible, setSplashVisible] = useState(true);

  useEffect(() => {
    const t = setTimeout(() => setSplashVisible(false), 1600);
    return () => clearTimeout(t);
  }, []);

  return (
    <>
      {/* 🔥 SPLASH SCREEN */}
      {splashVisible && (
        <div className="fixed inset-0 z-50 flex flex-col items-center justify-center bg-[#f8f8f6]">
          <GlobeLogo size={120} />
          <h1 className="mt-4 text-3xl font-bold tracking-[10px] text-gray-800">
            VISTA
          </h1>
          <p className="text-xs tracking-widest text-gray-400 uppercase mt-2">
            Smart Transit Assistant
          </p>
        </div>
      )}

      {/* 🔥 MAIN CONTENT */}
      {!splashVisible && (
        <Layout>
          {/* HERO */}
          <section className="grid md:grid-cols-2 min-h-[calc(100vh-60px)]">

            {/* LEFT */}
            <div className="flex flex-col justify-center px-4 sm:px-6 md:px-12 py-10">

              {/* Logo */}
              <div className="flex items-center gap-3 mb-6">
                <GlobeLogo size={40} />
                <div>
                  <h1 className="text-xl md:text-2xl font-bold tracking-widest">
                    VISTA
                  </h1>
                  <p className="text-[10px] text-gray-400 uppercase tracking-wider">
                    Smart Transit
                  </p>
                </div>
              </div>

              {/* Badge */}
              <div className="inline-flex items-center gap-2 bg-green-100 text-green-700 px-3 py-1 rounded-full text-xs font-semibold w-fit mb-4">
                ● VIRAR → BORIVALI
              </div>

              {/* Heading */}
              <h2 className="text-2xl sm:text-3xl md:text-5xl font-bold leading-tight mb-4">
                Navigate Mumbai Locals <br />
                <span className="text-green-600">
                  Using Just Your Voice
                </span>
              </h2>

              {/* Description */}
              <p className="text-gray-500 text-sm md:text-base max-w-md mb-6">
                Speak your destination. VISTA finds trains, platforms, and guides you door-to-door across Mumbai.
              </p>

              {/* Voice Wave */}
              <div className="mb-6">
                <VoiceWave />
              </div>

              {/* Buttons */}
              <div className="flex flex-col sm:flex-row gap-3">
                <Btn
                  className="w-full sm:w-auto"
                  onClick={() => {
                    onNavigate("location");
                    speak("Detecting your location");
                  }}
                >
                  Start Voice Navigation
                </Btn>

                <Btn
                  variant="secondary"
                  className="w-full sm:w-auto"
                  onClick={() => onNavigate("trains")}
                >
                  View Train Schedule
                </Btn>
              </div>

              {/* Stats */}
              <div className="flex justify-between mt-8 border-t pt-6 text-center">
                {[
                  { value: "7", label: "Stations" },
                  { value: "25km", label: "Route" },
                  { value: "3", label: "Train Types" },
                  { value: "24/7", label: "Support" },
                ].map((s) => (
                  <div key={s.label}>
                    <p className="text-lg md:text-xl font-bold">{s.value}</p>
                    <p className="text-xs text-gray-400 uppercase">
                      {s.label}
                    </p>
                  </div>
                ))}
              </div>
            </div>

            {/* RIGHT MAP */}
            <div className="relative h-[300px] sm:h-[400px] md:h-auto">
              <MapPanel className="absolute inset-0" />
            </div>
          </section>

          {/* HOW IT WORKS */}
          <section className="bg-gray-50 py-12 px-4 sm:px-6 md:px-12">
            <div className="text-center mb-10">
              <h3 className="text-xl md:text-2xl font-bold">
                How VISTA Works
              </h3>
              <p className="text-gray-400 text-sm">
                Simple 4-step journey guidance
              </p>
            </div>

            <div className="grid grid-cols-2 sm:grid-cols-2 md:grid-cols-4 gap-4">
              {HOW_IT_WORKS.map((item) => (
                <div
                  key={item.step}
                  className="bg-white p-4 rounded-xl border hover:shadow-md transition"
                >
                  <div className="text-2xl mb-2">{item.icon}</div>
                  <p className="text-xs text-green-600 font-semibold mb-1">
                    STEP {item.step}
                  </p>
                  <h4 className="font-semibold text-sm mb-1">
                    {item.title}
                  </h4>
                  <p className="text-xs text-gray-500">
                    {item.desc}
                  </p>
                </div>
              ))}
            </div>
          </section>
        </Layout>
      )}
    </>
  );
}
